                    } else {
                        box.classList.add('not-in-range');
                    }
                    if (index === mid) {
                        box.classList.add('highlight-mid');
                    }
                } else if (found && index === mid) {
                    box.classList.remove('highlight-range', 'highlight-mid');
                    box.classList.add('found');
                }

                // Add pointer labels
