                    statusDiv.classList.remove('found-text');
                    // Optionally highlight the last low/high bounds that crossed
                    if (low < currentArray.length && low >= 0) {
                         // This is tricky as low/high might be out of bounds after the loop
                         // Let's just indicate not found without specific box highlights
                         // unless we want to highlight where it *would* have been.
                    }
                }
                stepButton.disabled = true;
                return;
            }

            // Highlight active range
            for (let i = low; i <= high; i++) {
                if (boxes[i]) { // Ensure index exists
                    boxes[i].classList.add('active-range');
                }
            }

            // Highlight middle element
            if (low <= high) {
                const mid = Math.floor((low + high) / 2);
                if (boxes[mid]) { // Ensure index exists
                    boxes[mid].classList.add('middle-element');
                    statusDiv.textContent = `Comparing with middle element: ${currentArray[mid]} (Index: ${mid})`;
                    statusDiv.classList.remove('found-text', 'not-found-text');
                }
            } else {
                 // This case means low > high, so the search has conceptually finished "not found"
                 statusDiv.textContent = `Search finished. Target ${target} not found.`;
                 statusDiv.classList.add('not-found-text');
                 statusDiv.classList.remove('found-text');
                 searchFinished = true;
                 stepButton.disabled = true;
            }
        }

        function resetSearch() {
            currentArray = [...initialArray]; // Use a copy
            target = parseInt(targetInput.value);
            if (isNaN(target)) {
                alert("Please enter a valid number for the target.");
                targetInput.value = initialArray[0]; // Reset to a default valid value
                return;
            }

            low = 0;
            high = currentArray.length - 1;
            foundIndex = -1;
            searchFinished = false;
            stepButton.disabled = false;
            statusDiv.textContent = `Searching for ${target}...`;
            statusDiv.classList.remove('found-text', 'not-found-text');
            renderArray(); // Re-render to clear all previous states
        }

        function nextStep() {
            if (searchFinished || low > high) {
                searchFinished = true;
                updateVisualization(); // Final update for not found
                return;
            }

            const mid = Math.floor((low + high) / 2);
            const midValue = currentArray[mid];

            if (midValue === target) {
                foundIndex = mid;
                searchFinished = true;
            } else if (midValue < target) {
                low = mid + 1;
            } else { // midValue > target
                high = mid - 1;
            }
            updateVisualization();
        }

        // Event Listeners
        resetButton.addEventListener('click', resetSearch);
        stepButton.addEventListener('click', nextStep);

        // Initial setup
        resetSearch(); // Call once to initialize the array and controls
    </script>
