<body>
    <h1>Interactive Binary Search Visualizer</h1>

    <div id="array-container">
        <!-- Array boxes will be rendered here by JavaScript -->
    </div>

    <div id="controls">
        <label for="targetInput">Target Value:</label>
        <input type="number" id="targetInput" value="45" placeholder="Enter target">
        <button id="stepButton">Step Search</button>
        <button id="resetButton">Reset</button>
    </div>

    <div id="result">
        <!-- Search result will be displayed here -->
    </div>

    <div id="legend">
        <div class="key-item"><div class="key-color" style="background-color: #ecf0f1;"></div>Default</div>
        <div class="key-item"><div class="key-color" style="background-color: #d6eaf8; border-color: #3498db;"></div>Current Search Range</div>
        <div class="key-item"><div class="key-color" style="background-color: #f1c40f; border-color: #e67e22;"></div>Middle Element (Mid)</div>
        <div class="key-item"><div class="key-color" style="background-color: #2ecc71; border-color: #27ae60;"></div>Target Found!</div>
        <div class="key-item"><div class="key-color" style="background-color: #e74c3c; border-color: #c0392b;"></div>Not in Search Range / Not Found</div>
    </div>

    <div id="info">
        <p>This tool visualizes the binary search algorithm. Enter a target number and click "Step Search" to see the algorithm in action.</p>
        <p>Binary search works on <strong>sorted arrays</strong>. It repeatedly divides the search interval in half. If the value of the search key is less than the item in the middle of the interval, narrow the interval to the lower half. Otherwise, narrow it to the upper half. It continues until the value is found or the interval is empty.</p>
    </div>

    <script>
        const initialArray = [5, 12, 18, 23, 30, 37, 41, 45, 50, 55, 60, 68, 72, 79, 85, 90, 95];
        let currentArray = [];
        let low = 0;
        let high = 0;
        let target = null;
        let found = false;
        let searchActive = false;

        const arrayContainer = document.getElementById('array-container');
        const targetInput = document.getElementById('targetInput');
        const stepButton = document.getElementById('stepButton');
        const resetButton = document.getElementById('resetButton');
        const resultDisplay = document.getElementById('result');

        function renderArray() {
            arrayContainer.innerHTML = '';
            currentArray.forEach((number, index) => {
                const box = document.createElement('div');
                box.classList.add('array-box');
                box.textContent = number;
                box.dataset.index = index; // Store index for easy reference
                arrayContainer.appendChild(box);
            });
            updateVisualization(); // Apply initial highlights if any
        }

        function resetSearch() {
            currentArray = [...initialArray]; // Copy initial array
            low = 0;
            high = currentArray.length - 1;
            target = parseInt(targetInput.value);
            found = false;
            searchActive = true;

            resultDisplay.textContent = '';
            resultDisplay.className = ''; // Clear result styling
            stepButton.disabled = false;
            targetInput.disabled = false;

            renderArray(); // Re-render with default styling
            updateVisualization(); // Apply initial range highlight
        }

        function updateVisualization() {
            const boxes = document.querySelectorAll('.array-box');
            boxes.forEach((box, index) => {
                box.classList.remove('highlight-range', 'highlight-mid', 'highlight-found', 'highlight-not-found');
                // Reset to default background
                box.style.backgroundColor = '';
                box.style.borderColor = '';
                box.style.color = '';
                box.style.transform = '';

                if (!searchActive) {
                    // No search active, all default
                    return;
                }

                if (found && index === low) { // If found, low points to the found index
                    box.classList.add('highlight-found');
                } else if (!found && (low > high)) {
                    // Search finished, not found. Mark out-of-range elements
                    box.classList.add('highlight-not-found');
                } else if (index >= low && index <= high) {
                    box.classList.add('highlight-range');
                } else {
                    box.classList.add('highlight-not-found'); // Elements outside the current search range
                }
            });

            // Highlight mid element if search is active and not finished
            if (searchActive && low <= high) {
                const mid = Math.floor((low + high) / 2);
                if (boxes[mid]) {
                    boxes[mid].classList.add('highlight-mid');
                    // Ensure mid element also gets range highlight if it's not the final found element
                    if (!boxes[mid].classList.contains('highlight-found')) {
                         boxes[mid].classList.add('highlight-range');
                    }
                }
            }
        }

        function stepSearch() {
            if (!searchActive) {
                resultDisplay.textContent = 'Please enter a target and click Reset to start a new search.';
                resultDisplay.classList.add('result-not-found');
                return;
            }

            if (low > high) {
                resultDisplay.textContent = `Target ${target} not found in the array.`;
                resultDisplay.classList.add('result-not-found');
                stepButton.disabled = true;
                searchActive = false;
                updateVisualization(); // Final update to show all non-found
                return;
            }

            const mid = Math.floor((low + high) / 2);
            const midValue = currentArray[mid];

            // Remove previous mid highlight before applying new ones
            document.querySelectorAll('.array-box.highlight-mid').forEach(box => {
                box.classList.remove('highlight-mid');
            });

            if (midValue === target) {
                found = true;
                low = mid; // Point low to the found index for consistent highlighting
                resultDisplay.textContent = `Target ${target} found at index ${mid}!`;
                resultDisplay.classList.add('result-found');
                stepButton.disabled = true;
                searchActive = false;
                updateVisualization(); // Final update to show found element
                return;
            } else if (midValue < target) {
                low = mid + 1;
            } else { // midValue > target
                high = mid - 1;
            }
            updateVisualization();
        }

        // Event Listeners
        stepButton.addEventListener('click', stepSearch);
        resetButton.addEventListener('click', resetSearch);
        targetInput.addEventListener('change', () => {
            // Re-validate target and reset if changed
            target = parseInt(targetInput.value);
            if (isNaN(target)) {
                targetInput.value = '';
                resultDisplay.textContent = 'Please enter a valid number.';
                resultDisplay.classList.add('result-not-found');
                stepButton.disabled = true;
            } else {
                resetSearch(); // Reset search state when target changes
            }
        });
        targetInput.addEventListener('keyup', (event) => {
            if (event.key === 'Enter') {
                stepSearch();
            }
        });


        // Initial setup
        resetSearch(); // Call reset to initialize the array and search state
    </script>
</body>
</html>
